module RefModule (
    input clk, wen,
    input [5:0] waddr,
    input [5:0] raddr1,
    input [5:0] raddr2,
    input [31:0] wdata,
    output reg [31:0] rdata1,
    output reg [31:0] rdata2
);

    reg [31:0] obf_regs [0:31];

    always @(posedge clk) begin
        if (wen) begin
            obf_regs[waddr] <= wdata;
        end
    end

    assign rdata1 = obf_regs[raddr1];
    assign rdata2 = obf_regs[raddr2];

endmodule
